import{_ as a,o as i,c as t,a2 as l}from"./chunks/framework.BflysNKA.js";const c=JSON.parse('{"title":"为什么需要 小蓝中转站 网关？","description":"","frontmatter":{},"headers":[],"relativePath":"intro/overview.md","filePath":"intro/overview.md","lastUpdated":1778577020000}'),n={name:"intro/overview.md"};function s(p,e,d,r,o,h){return i(),t("div",null,[...e[0]||(e[0]=[l(`<h1 id="为什么需要-xiaolan-ai-网关" tabindex="-1">为什么需要 小蓝中转站 网关？ <a class="header-anchor" href="#为什么需要-xiaolan-ai-网关" aria-label="Permalink to &quot;为什么需要 小蓝中转站 网关？&quot;">​</a></h1><p>已经熟悉 OpenAI 兼容接口的用户，可以直接查看 <a href="/guide/create-key">创建专属 Key</a> 和 <a href="/deploy/claude-code">工具接入指南</a>。</p><h2 id="xiaolan-ai-解决什么" tabindex="-1">小蓝中转站 解决什么 <a class="header-anchor" href="#xiaolan-ai-解决什么" aria-label="Permalink to &quot;小蓝中转站 解决什么&quot;">​</a></h2><p>配置 Claude Code、Gemini CLI、Codex、Cherry Studio 等工具时，常见问题集中在三个方面：多个平台账号、不同接口格式、不同 Key 和账单分散管理。</p><p>小蓝中转站 提供统一模型网关，把这些工具接到同一个接口入口。</p><p>接入后的请求链路：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>你的工具  ←→  小蓝中转站 Endpoint  ←→  可用模型</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>第一次接入时，更容易混在一起的其实还有三件事：</p><ul><li><strong>下载工具</strong>：去各自官方入口下载安装</li><li><strong>创建 Key</strong>：在 小蓝中转站控制台生成专属凭证</li><li><strong>把工具接到网关</strong>：按各工具自己的协议填写地址、Key 和模型</li></ul><p>把这三件事分开以后，排障会清楚很多。<br> 很多“工具装好了却不能用”的问题，最后都不是下载层，而是 Key、模型或地址层。</p><p>对 Codex、OpenAI SDK 这类直接填写 OpenAI Base URL 的工具，常用配置只需要记住三项：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>Base URL: https://xiaolan1.cn/v1</span></span>
<span class="line"><span>API Key: 控制台创建的 Key</span></span>
<span class="line"><span>Model: 模型广场复制的模型名</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Cherry Studio 也是 OpenAI 兼容思路，但它的服务商地址栏按官方当前说明更适合填写根地址 <code>https://xiaolan1.cn</code>，再由客户端自己继续补后面的兼容路径。</p><h2 id="为什么同一个网关-不同工具的地址却不一样" tabindex="-1">为什么同一个网关，不同工具的地址却不一样 <a class="header-anchor" href="#为什么同一个网关-不同工具的地址却不一样" aria-label="Permalink to &quot;为什么同一个网关，不同工具的地址却不一样&quot;">​</a></h2><p>第一次接入最容易踩的坑，就是把所有工具都当成完全一样的 OpenAI 兼容客户端来填。</p><p>实际上，不同工具对 Base URL 的要求并不完全一样：</p><table tabindex="0"><thead><tr><th>工具</th><th>地址应该怎么填</th><th>原因</th></tr></thead><tbody><tr><td>Codex / OpenAI SDK / 大多数 OpenAI 兼容工具</td><td><code>https://xiaolan1.cn/v1</code></td><td>工具本身按 OpenAI 兼容接口发请求</td></tr><tr><td>Claude Code</td><td><code>https://xiaolan1.cn</code></td><td>Claude Code 自己继续拼 Anthropic 协议路径</td></tr><tr><td>Gemini CLI</td><td><code>https://xiaolan1.cn</code></td><td>Gemini CLI 自己继续拼 Gemini API 路径</td></tr><tr><td>Cherry Studio</td><td><code>https://xiaolan1.cn</code></td><td>客户端自己继续补 OpenAI 兼容路径</td></tr></tbody></table><p>只要这一层填错，就很容易出现这类现象：</p><ul><li>Key 看起来没问题，却一直 404</li><li>能启动客户端，却拉不到模型</li><li>明明装好了工具，却始终发不出第一条正常请求</li></ul><h2 id="为什么不是每个工具都直接连官方" tabindex="-1">为什么不是每个工具都直接连官方 <a class="header-anchor" href="#为什么不是每个工具都直接连官方" aria-label="Permalink to &quot;为什么不是每个工具都直接连官方&quot;">​</a></h2><p>很多用户第一次接触时，会把“下载工具”和“把工具接到哪个网关”混在一起。其实这是两件不同的事：</p><ul><li><strong>下载工具</strong>：仍然优先从各自官方入口下载</li><li><strong>接入模型</strong>：通过 小蓝中转站 统一管理地址、Key、模型和账单</li></ul><p>这样做的直接好处是：</p><ol><li>不同工具不需要分别记不同平台的账号和充值方式</li><li>更容易按设备、工具、项目拆分 Key</li><li>排障时可以直接在同一个控制台看日志和消耗</li><li>模型名、分组和价格都能在同一个模型广场确认</li></ol><p>也就是说，小蓝中转站 不是替代工具本身，而是把“工具怎么接模型”这件事统一起来。</p><h2 id="核心体验优势" tabindex="-1">核心体验优势 <a class="header-anchor" href="#核心体验优势" aria-label="Permalink to &quot;核心体验优势&quot;">​</a></h2><h3 id="统一-endpoint" tabindex="-1">统一 Endpoint <a class="header-anchor" href="#统一-endpoint" aria-label="Permalink to &quot;统一 Endpoint&quot;">​</a></h3><p>大多数支持 OpenAI 兼容接口的开发工具，只需要配置这一个地址：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn/v1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="密钥沙盒化管理" tabindex="-1">密钥沙盒化管理 <a class="header-anchor" href="#密钥沙盒化管理" aria-label="Permalink to &quot;密钥沙盒化管理&quot;">​</a></h3><p>可以按设备、工具或项目分配独立 Key。发现配置泄露或不再需要时，在控制台停用或删除对应 Key。</p><h3 id="模型矩阵自由切换" tabindex="-1">模型矩阵自由切换 <a class="header-anchor" href="#模型矩阵自由切换" aria-label="Permalink to &quot;模型矩阵自由切换&quot;">​</a></h3><p>在控制台的“模型广场”查看当前可用模型、模型名和费率，复制完整模型名后写入客户端：</p><p><a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">https://xiaolan1.cn/pricing</a></p><h3 id="账单所见即所得" tabindex="-1">账单所见即所得 <a class="header-anchor" href="#账单所见即所得" aria-label="Permalink to &quot;账单所见即所得&quot;">​</a></h3><p>余额和消费明细按人民币计算。控制台日志可以按 Key、模型和时间范围查看请求消耗。</p><h2 id="统一入口不等于所有工具都用同一套参数" tabindex="-1">统一入口不等于所有工具都用同一套参数 <a class="header-anchor" href="#统一入口不等于所有工具都用同一套参数" aria-label="Permalink to &quot;统一入口不等于所有工具都用同一套参数&quot;">​</a></h2><p>第一次接入最容易踩的坑，就是把所有工具都当成完全一样的 OpenAI 兼容客户端来填。</p><p>大多数工具确实使用：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn/v1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>但 Claude Code 是例外。Claude Code 读取的是 Anthropic 协议变量，Base URL 需要填写根地址：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>不要给 Claude Code 手动补 <code>/v1</code>。<br> Codex、OpenAI SDK 这类 OpenAI 兼容工具，继续填写 <code>https://xiaolan1.cn/v1</code>。<br> Cherry Studio 则更适合填写根地址 <code>https://xiaolan1.cn</code>，让客户端自己补路径。</p><p>Gemini CLI 当前版本也是例外。它读取的是 <code>GOOGLE_GEMINI_BASE_URL</code> 和 <code>GEMINI_API_KEY</code>，地址填写根地址 <code>https://xiaolan1.cn</code>，再由 CLI 自己拼接 <code>/v1beta/models/...</code> 这类 Gemini API 路径。</p><p>把这一点分清楚，能少掉很多“明明 Key 没问题，却始终连不上”的排障时间。</p><h2 id="跑通第一条链路以后-排障为什么会轻很多" tabindex="-1">跑通第一条链路以后，排障为什么会轻很多 <a class="header-anchor" href="#跑通第一条链路以后-排障为什么会轻很多" aria-label="Permalink to &quot;跑通第一条链路以后，排障为什么会轻很多&quot;">​</a></h2><p>当你已经让某一个工具先正常回复过一次，后面再遇到问题时，范围通常就能缩小到：</p><ul><li>当前换的模型是否超出这把 Key 的分组或模型权限</li><li>当前项目目录是否有额外配置覆盖默认值</li><li>当前终端是否读到了新的环境变量</li><li>当前工具是否还停留在旧服务商、旧模型或旧会话</li></ul><p>这也是为什么文档一直建议先选一条最短路径：</p><ul><li>先聊天试通接口：Cherry Studio</li><li>先在终端里改代码：Claude Code</li><li>已经熟悉 OpenAI CLI：Codex</li><li>想要长上下文终端助手：Gemini CLI</li></ul><h2 id="key-安全" tabindex="-1">Key 安全 <a class="header-anchor" href="#key-安全" aria-label="Permalink to &quot;Key 安全&quot;">​</a></h2><ul><li>API Key 只保存在本地环境变量、<code>.env</code> 文件、可信客户端或密码管理器中。</li><li>不要把包含 Key 的配置文件提交到 Git 仓库。</li><li>共享服务器、测试脚本和公网服务建议使用单独 Key，并设置额度上限。</li></ul><h2 id="跑通后你会得到什么" tabindex="-1">跑通后你会得到什么 <a class="header-anchor" href="#跑通后你会得到什么" aria-label="Permalink to &quot;跑通后你会得到什么&quot;">​</a></h2><p>当某个工具已经能通过 小蓝中转站 正常回复时，通常说明下面几件事已经同时成立：</p><ul><li>当前网络能够访问 小蓝中转站 网关</li><li>你的账号和余额状态正常</li><li>这把 Key 处于可用状态</li><li>当前分组和模型权限允许调用目标模型</li><li>Base URL、API Key、Model 至少这三项没有填错</li></ul><p>这也是为什么文档一直强调先跑通一条最小链路。只有先证明基础链路是通的，后面继续换模型、换工具、换客户端才会更稳。</p><h2 id="常见接入方式" tabindex="-1">常见接入方式 <a class="header-anchor" href="#常见接入方式" aria-label="Permalink to &quot;常见接入方式&quot;">​</a></h2><ul><li>图形界面聊天：Cherry Studio</li><li>终端编程：Claude Code</li><li>OpenAI CLI 工作流：Codex</li><li>长上下文终端助手：Gemini CLI</li><li>自己写脚本：OpenAI 兼容接口</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/guide/registration">注册账号</a></li><li><a href="/guide/create-key">创建专属 Key</a></li><li><a href="/guide/quick-start">快速接入</a></li><li><a href="/support/faq">常见问题</a></li></ul>`,60)])])}const b=a(n,[["render",s]]);export{c as __pageData,b as default};
